local LFightHud = LXImport(".LFightHud")
local LFightHudData = LXImport("..Data.LFightHudData")

-----------------------------------------------------------------
---@class LFightObjectHud
local LFightObjectHud = LxClass("LFightObjectHud", nil)

-----------------------------------------------------------------
function LFightObjectHud:LFightObjectHud(battleCache, tarObj)
	self._tarObj = tarObj

	---@type LFightCache
	self._battleCache = battleCache

	---@type table<number, LFightHud[]>
	self._hudList = {}

	self._maxGroup = 0

	self._hudGroupSort = {}

	self._idx = 0

	self:InitColIndex()
end

-----------------------------------------------------------------
function LFightObjectHud:InitColIndex()
	local gridIndex = self._tarObj:GetIndex() or 0
	local side = self._tarObj:GetSide()
	if side == LFightConst.SIDE_TEAM_A then
		if gridIndex > 6 then
			self._colIndex = 1
		elseif gridIndex > 3 then
			self._colIndex = 2
		else
			self._colIndex = 3
		end
	else
		if gridIndex > 6 then
			self._colIndex = 3
		elseif gridIndex > 3 then
			self._colIndex = 2
		else
			self._colIndex = 1
		end
	end
end

-----------------------------------------------------------------
---@param lBattleSkill LFightSkill
function LFightObjectHud:CreateHud(startTime,hudData,lBattleSkill)
	if self._isDestroy then return end
	local hudDataList = self:CalcHurtWaveData(hudData.changeType,hudData.hurt,hudData.playNum)
	for k,v in ipairs(hudDataList) do
		---@type LFightHud
		local hud = LFightHud:New(self._battleCache, self._colIndex)
		hud:Create(self._idx,{v},hudData)
		hud:SetTarObj(self._tarObj)
		hud:SetBattleSkill(lBattleSkill)

		hud:SetStartTime(startTime + (v:GetDelay() or 0))

		self:AddHud(hud)
		self._idx = self._idx + 1
	end
end
-----------------------------------------------------------------
--按次数分割伤害
function LFightObjectHud:CalcHurtWaveData(changeType,hurt,playNum)
	if not hurt then -- buff类型的hud数据
		return {self:GenerateHudData(changeType,0,0,0)}
	end

	if #playNum < 1 then
		return {self:GenerateHudData(changeType,hurt,0,0)}
	end

	local floatHurtY = 30
	local hurtDataList = {}
	local totalHurt = hurt

	local timeDelay = 0
	local oneHurt = nil
	for i, v in ipairs(playNum) do
		oneHurt =  math.floor(v[2] * hurt)
		totalHurt = totalHurt - oneHurt
		table.insert(hurtDataList,self:GenerateHudData(changeType,oneHurt,timeDelay,floatHurtY))
		timeDelay = v[1]
	end
	if totalHurt > 0 then
		table.insert(hurtDataList,self:GenerateHudData(changeType,totalHurt,timeDelay,floatHurtY))
	end
	return hurtDataList
end

--hud数据
function LFightObjectHud:GenerateHudData(changeType,hurt,delay,floatHurtY)
	return LFightHudData:New(changeType,hurt,delay,floatHurtY)
end

function LFightObjectHud:AddHud(hud)
	local group = hud:GetGroup()
	local vList = self._hudList[group]
	if not vList then
		vList = {}
		self._hudList[group] = vList
	end
	table.insert(vList,hud)

	self._hudGroupSort[group] = true
	if group > self._maxGroup then
		self._maxGroup = group
	end
end

-----------------------------------------------------------------
function LFightObjectHud:OnRun(time)
	if self._isDestroy then return end
	local hudList = self._hudList
	for k=0, self._maxGroup do
		self:DoRunHudList(k, hudList[k], time)
	end
end

-----------------------------------------------------------------
local function sortHudFunc(a, b)
	local timeA = a:GetStartTime()
	local timeB = b:GetStartTime()
	if timeA ~= timeB then
		return timeA < timeB
	end
	return a:GetIdx() < b:GetIdx()
end

function LFightObjectHud:DoRunHudList(group, hudList, time)
	if not hudList or #hudList == 0 then return end
	if self._hudGroupSort[group] then
		self._hudGroupSort[group] = nil
		if(#hudList > 1) then
			table.sort(hudList, sortHudFunc)
		end
	end
	local delIndex = {}
	local lastPlayIndex = 0
	local oldPlaying = false
	for k,v in ipairs(hudList) do
		oldPlaying = v:IsPlaying()
		if not v:OnRun(time) then
			table.insert(delIndex,k)
		else
			if not oldPlaying and v:IsPlaying() then
				lastPlayIndex = k
			end
		end
	end

	local delLen = #delIndex
	for k=delLen,1,-1 do
		local hud = table.remove(hudList,delIndex[k])
		hud:Destroy()
	end

	if group == LFightConst.HUD_GROUP_HURT or group == LFightConst.HUD_GROUP_BUFF then
		--lastPlayIndex = lastPlayIndex - delLen
		--if lastPlayIndex > 1 then
		--	--伤害数字 和buff 名字， 新出现的会把旧的往上顶一段距离
		--	local upY = 20
		--	for k=lastPlayIndex-1,1,-1  do
		--		local hud = hudList[k]
		--		hud:UpBtNodePos(upY)
		--		upY = upY + 20
		--	end
		--end
		local playingList = {}
		for k,v in ipairs(hudList) do
			if v:IsPlaying() then
				table.insert(playingList,v)
			end
		end
		local cnt = #playingList
		for k,v in ipairs(playingList) do
			v:SetGroupOffset(cnt - k)
		end
	end
end

------------------------------------------------------------------
function LFightObjectHud:ClearHud()
	if self._hudList ~= nil then
		for k, vList in pairs(self._hudList) do
			for _, v in ipairs(vList) do
				v:Destroy()
			end
			self._hudList[k] = nil
		end
		self._hudList = nil
	end
end
-----------------------------------------------------------------

function LFightObjectHud:Destroy()
	if self._isDestroy then return end
	self:ClearHud()
	self._battleCache = nil
	table.removeall(self)
	self._isDestroy = true
end
-----------------------------------------------------------------

return LFightObjectHud